import React, { useState, useEffect } from 'react';
import axios from 'axios';

const AdminPanel = () => {
  const [activeTab, setActiveTab] = useState('create'); 
  const [postType, setPostType] = useState('blog'); 
  const [category, setCategory] = useState('Electronics');
  const [formData, setFormData] = useState({ title: '', description: '', loc: '', salary: '', type: 'On-site' });
  const [file, setFile] = useState(null);
  const [items, setItems] = useState([]); 
  const [inquiries, setInquiries] = useState([]); // Contact Data State

  const [isEditing, setIsEditing] = useState(false);
  const [editData, setEditData] = useState(null);

  // 1. Fetch Blogs/Jobs (Fix: URL structure checked)
  const fetchItems = async () => {
    try {
      const url = postType === 'job' 
        ? 'http://localhost:5001/api/jobs' 
        : `http://localhost:5001/api/blog/${category}`;
      const res = await axios.get(url);
      setItems(res.data);
    } catch (err) { 
      console.error("Fetch Items Error:", err); 
      setItems([]); // Error par blank array set karein
    }
  };

  // 2. Fetch Contact Inquiries
  const fetchInquiries = async () => {
    try {
      const res = await axios.get('http://localhost:5001/api/contact');
      setInquiries(res.data);
    } catch (err) { 
      console.error("Fetch Inquiries Error:", err); 
    }
  };

  // Trigger data fetching based on tab
  useEffect(() => {
    if (activeTab === 'manage') fetchItems();
    if (activeTab === 'inquiries') fetchInquiries();
  }, [activeTab, postType, category]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      let response;
      if (postType === 'job') {
        response = await axios.post('http://localhost:5001/api/admin/jobs', formData);
      } else {
        const data = new FormData();
        data.append('category', category); 
        data.append('title', formData.title);
        data.append('description', formData.description);
        if (file) data.append('image', file);
        response = await axios.post('http://localhost:5001/api/admin/blog', data);
      }
      if (response.status === 201) {
        alert("Published Successfully!");
        setFormData({ title: '', description: '', loc: '', salary: '', type: 'On-site' });
        setFile(null);
      }
    } catch (err) { alert("Error publishing content"); }
  };

  const handleDelete = async (id, type) => {
    if (window.confirm("Kyan aap ise delete karna chahte hain?")) {
      try {
        const endpoint = type === 'inquiry' ? 'contact' : (postType === 'job' ? 'jobs' : 'blog');
        await axios.delete(`http://localhost:5001/api/admin/${endpoint}/${id}`);
        type === 'inquiry' ? fetchInquiries() : fetchItems();
        alert("Deleted!");
      } catch (err) { alert("Delete Failed"); }
    }
  };

  return (
    <div className="flex min-h-screen bg-gray-50 pt-10 font-sans">
      {/* SIDEBAR - Brand spacing fixed */}
      <div className="w-80 bg-black text-white p-8 fixed h-full shadow-2xl overflow-y-auto">
        <div className="mt-16 mb-12">
          <h2 className="text-2xl font-black text-orange-500 tracking-tighter leading-none">
            Rhodeotech <br /> <span className="text-white text-4xl">ADMIN</span>
          </h2>
        </div>

        <div className="space-y-2">
          <button onClick={() => setActiveTab('create')} className={`w-full text-left p-4 rounded-2xl font-bold transition-all ${activeTab === 'create' ? 'bg-orange-600 shadow-lg' : 'text-gray-400 hover:text-white'}`}>➕ Create New</button>
          <button onClick={() => setActiveTab('manage')} className={`w-full text-left p-4 rounded-2xl font-bold transition-all ${activeTab === 'manage' ? 'bg-orange-600 shadow-lg' : 'text-gray-400 hover:text-white'}`}>⚙️ Manage All</button>
          <button onClick={() => setActiveTab('inquiries')} className={`w-full text-left p-4 rounded-2xl font-bold transition-all ${activeTab === 'inquiries' ? 'bg-orange-600 shadow-lg' : 'text-gray-400 hover:text-white'}`}>📩 Inquiries</button>
        </div>

        {(activeTab !== 'inquiries') && (
          <div className="mt-10 border-t border-gray-800 pt-6 space-y-6">
             <div className="flex bg-gray-900 p-1.5 rounded-xl border border-gray-800">
               <button onClick={() => setPostType('job')} className={`flex-1 py-2.5 rounded-lg text-[10px] font-black uppercase tracking-[0.2em] transition-all ${postType === 'job' ? 'bg-white text-black' : 'text-gray-500'}`}>Jobs</button>
               <button onClick={() => setPostType('blog')} className={`flex-1 py-2.5 rounded-lg text-[10px] font-black uppercase tracking-[0.2em] transition-all ${postType === 'blog' ? 'bg-white text-black' : 'text-gray-500'}`}>Blogs</button>
             </div>
             {postType === 'blog' && (
               <select value={category} onChange={(e) => setCategory(e.target.value)} className="w-full bg-gray-900 text-white p-4 rounded-xl text-sm border border-gray-800 outline-none">
                 <option value="Electronics">Electronics</option>
                 <option value="Electrical">Electrical</option>
                 <option value="Chemical">Chemical</option>
                 <option value="Industries">Industries</option>
               </select>
             )}
          </div>
        )}
      </div>

      {/* MAIN CONTENT AREA */}
      <div className="flex-1 ml-80 p-12">
        {activeTab === 'create' && (
          <div className="max-w-3xl bg-white rounded-[3rem] p-12 shadow-sm border border-gray-100">
            <h1 className="text-5xl font-black italic tracking-tighter text-gray-900 mb-10">Add Content</h1>
            <form onSubmit={handleSubmit} className="space-y-5">
              <input required className="w-full p-5 bg-gray-50 rounded-2xl font-bold outline-none" placeholder="Title" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} />
              {postType === 'blog' ? (
                <>
                  <textarea rows="6" className="w-full p-5 bg-gray-50 rounded-2xl font-bold outline-none" placeholder="Description" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} />
                  <input type="file" onChange={(e) => setFile(e.target.files[0])} className="block mx-auto" />
                </>
              ) : (
                <div className="grid grid-cols-2 gap-5">
                  <input className="w-full p-5 bg-gray-50 rounded-2xl font-bold" placeholder="Location" value={formData.loc} onChange={e => setFormData({...formData, loc: e.target.value})} />
                  <input className="w-full p-5 bg-gray-50 rounded-2xl font-bold" placeholder="Salary" value={formData.salary} onChange={e => setFormData({...formData, salary: e.target.value})} />
                </div>
              )}
              <button className="w-full bg-black text-white py-6 rounded-[2rem] font-black text-xl hover:bg-orange-600 transition-all uppercase">Publish Now</button>
            </form>
          </div>
        )}

        {activeTab === 'manage' && (
          <div className="max-w-4xl bg-white rounded-[3rem] p-12 shadow-sm border border-gray-100">
            <h1 className="text-4xl font-black italic text-gray-900 mb-10 tracking-tighter">Active Repository</h1>
            <div className="space-y-4">
              {items.length > 0 ? items.map(item => (
                <div key={item._id} className="flex items-center justify-between p-7 bg-gray-50 rounded-[2.5rem] border border-gray-100">
                  <div>
                    <h3 className="font-black text-xl">{item.title}</h3>
                    <span className="text-orange-500 text-[10px] font-black uppercase tracking-widest">{item.loc || item.category}</span>
                  </div>
                  <div className="flex gap-3">
                    <button onClick={() => handleDelete(item._id, 'item')} className="bg-red-50 text-red-500 px-6 py-2 rounded-xl font-black text-[10px] tracking-widest">PURGE</button>
                  </div>
                </div>
              )) : <p className="text-center py-10 text-gray-400 font-bold uppercase">No data found in this category.</p>}
            </div>
          </div>
        )}

        {/* INQUIRIES TAB: Yahan sara Contact form ka data aayega */}
        {activeTab === 'inquiries' && (
          <div className="max-w-5xl bg-white rounded-[3rem] p-12 shadow-sm border border-gray-100">
            <h1 className="text-5xl font-black italic tracking-tighter text-gray-900 mb-10">Contact Inquiries</h1>
            <div className="grid gap-6">
              {inquiries.length > 0 ? inquiries.map((iq) => (
                <div key={iq._id} className="p-8 bg-gray-50 rounded-[2.5rem] border border-gray-100 hover:shadow-xl transition-all">
                  <div className="flex justify-between items-start mb-4">
                    <div>
                      <h3 className="text-2xl font-black text-gray-900">{iq.fullName}</h3>
                      <p className="text-orange-600 font-bold text-sm">{iq.email}</p>
                    </div>
                    <span className="bg-white px-4 py-2 rounded-full text-[10px] font-black uppercase border border-gray-200">
                      {iq.sector || 'General'}
                    </span>
                  </div>
                  <div className="bg-white p-6 rounded-2xl border border-gray-100 mb-4">
                    <p className="text-gray-600 font-medium italic">"{iq.message}"</p>
                  </div>
                  <div className="flex justify-between items-center px-2">
                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Company: {iq.company || 'Personal'}</p>
                    <button onClick={() => handleDelete(iq._id, 'inquiry')} className="text-red-500 font-black text-[10px] uppercase hover:text-red-700">Delete Record</button>
                  </div>
                </div>
              )) : <p className="text-center py-20 text-gray-300 font-bold uppercase">No inquiries submitted yet.</p>}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminPanel;
